273	// sendReceivePack encodes and POSTs a receive-pack request, then decodes the report.
274	func sendReceivePack(
275		ctx context.Context,
276		conn Conn,
277		req *packp.UpdateRequests,
278		packData io.Reader,
279		verbose bool,
280		onRejection func(plumbing.ReferenceName, string),
281	) error {
282		var header bytes.Buffer
283		if err := req.Encode(&header); err != nil {
284			return fmt.Errorf("encode update-request: %w", err)
285		}
286		// The push body is io.MultiReader(header, packData); packData comes
287		// from a live upload-pack pipe and isn't rewindable, so a mid-stream
288		// 401 can't trigger PostRPCStreamBody's normal helper retry. Probe
289		// for auth requirements with a same-shape POST first.
290		if hc, ok := conn.(*HTTPConn); ok {
291			hc.EnsureAuthForService(ctx, transport.ReceivePackService)
292		}
293		body := io.Reader(bytes.NewReader(header.Bytes()))
294		if packData != nil {
295			body = io.MultiReader(body, packData)
296		}
297		reader, err := PostRPCStreamBody(ctx, conn, transport.ReceivePackService, body, false, "receive-pack push")
298		if err != nil {
299			return fmt.Errorf("target receive-pack: %w", err)
300		}
301		defer reader.Close()
302	
303		// Unwrap sideband if negotiated; stream server-side progress to stderr
304		// when verbose so long-running pushes show "Resolving deltas ..." etc.
305		var respReader io.Reader = reader
306		switch {
307		case req.Capabilities.Supports(capability.Sideband64k):
308			dem := sideband.NewDemuxer(sideband.Sideband64k, reader)
309			dem.Progress = progressSink(verbose, "target: ", conn.ProgressWriter())
310			respReader = dem
311		case req.Capabilities.Supports(capability.Sideband):
312			dem := sideband.NewDemuxer(sideband.Sideband, reader)
313			dem.Progress = progressSink(verbose, "target: ", conn.ProgressWriter())
314			respReader = dem
315		}
316	
317		if req.Capabilities.Supports(capability.ReportStatus) {
318			report := &packp.ReportStatus{}
319			if err := report.Decode(respReader); err != nil {
320				return fmt.Errorf("decode report-status: %w", err)
321			}
322			if onRejection == nil {
323				if err := report.Error(); err != nil {
324					return fmt.Errorf("report-status: %w", asRefRejectedError(annotateLeaseFailure(err)))
325				}
326				return nil
327			}
328			if report.UnpackStatus != "" && report.UnpackStatus != "ok" {
329				return fmt.Errorf("report-status: unpack error: %s", report.UnpackStatus)
330			}
331			for _, cs := range report.CommandStatuses {
332				if cs.Status == "" || cs.Status == "ok" {
333					continue
334				}
335				onRejection(cs.ReferenceName, cs.Status)
336			}
337		}
338		return nil
339	}
