// emptyPack returns the bytes of a valid packfile containing zero objects: the
// 12-byte header ("PACK", version 2, object count 0) followed by the trailing
// checksum over that header. The checksum algorithm follows the target's
// advertised object-format capability so SHA-256 repositories get a 32-byte
// trailer; everything else uses the 20-byte SHA-1 trailer.
func emptyPack(adv *packp.AdvRefs) []byte {
	header := []byte{'P', 'A', 'C', 'K', 0, 0, 0, 2, 0, 0, 0, 0}
	algo := crypto.SHA1
	if vals := adv.Capabilities.Get(capability.ObjectFormat); len(vals) > 0 && vals[0] == "sha256" {
		algo = crypto.SHA256
	}
	h := hash.New(algo)
	_, _ = h.Write(header)
	return h.Sum(header)
}

